            l_val = dfs(node.left) # 左子树能提供的最大收益
            r_val = dfs(node.right) # 右子树能提供的最大收益
            nonlocal ans
            ans = max(ans,l_val+r_val+node.val) # 更新全局最大路径和
            return max(max(l_val,r_val)+node.val,0)
        dfs(root)
        return ans

