        left,right = 0,len(nums)-1
        while left <= right:
            mid = (left+right) // 2
            if nums[mid] >= target:
                right = mid -1
            else:
                left = mid + 1
        return left # 第一个大于等于target的位置
    def searchRange(self, nums: List[int], target: int) -> List[int]:
        start = self.lower_bound(nums,target)
