        n,m = len(s),len(t)
        @cache
        def dfs(i:int,j:int) ->int: # dfs(i, j)表示：s[0~i] 和 t[0~j] 这两段字符串的最长公共子序列长度
            if i < 0  or j < 0:
                return 0
            if s[i] == t[j]:
                return dfs(i-1,j-1) + 1
            return max(dfs(i-1,j),dfs(i,j-1))# 选大的
        # 选大的
        return dfs(n-1,m-1)

class Solution:
    def minDistance(self, word1: str, word2: str) -> int:
        n = len(word1)
        m = len(word2)

        if n * m == 0:
            return n + m

        #D[i][j]表示word1的前 i 个字符，变成word2的前 j 个字符，最少需要多少步
        D = [ [0] * (m+1) for _ in range(n+1)]

        for i in range(n+1):
            D[i][0] = i
        for j in range(m+1):
            D[0][j] = j

        for i in range(1,n+1):
            for j in range(1,m+1):
                # 先把 word1 前 i-1 个字符变成 word2 前 j 个字符，然后再删除 word1 的第 i 个字符
                left = D[i-1][j] + 1
                down = D[i][j-1] + 1 # 插入
                left_down = D[i-1][j-1]  # 替换
                if word1[i-1] != word2[j-1]:
                    left_down += 1
                D[i][j] = min(left,down,left_down)

        return D[n][m]

class Solution:
    def singleNumber(self, nums: List[int]) -> int:
        x = 0
        for num in nums:
            x ^= num # 异或
        return x

class Solution:
    def majorityElement(self, nums: List[int]) -> int:
        votes = 0 # 当前候选人 x 的“票数优势”
        for num in nums:
            if votes == 0: x = num # 如果票数是 0，就换候选人
            votes += 1 if num == x else -1
        return x

class Solution:
    def sortColors(self, nums: List[int]) -> None:
        p0 = p1 = 0 # p0表示：下一个应该放 0 的位置
        # p1表示：下一个应该放 1 的位置
        for i,x in enumerate(nums):
            nums[i] = 2
            if x <= 1:
                nums[p1] = 1
                p1 += 1
            if x == 0:
                nums[p0] = 0
                p0 += 1
